"use client"

import { useEffect, useState } from "react"

import { supabase } from "@/lib/supabase"

import {
  getFactoryCurrency,
  getFactoryId,
} from "@/lib/factory"

import { formatCurrency } from "@/lib/format"

type ActivityItem = {
  type: string
  amount?: number
  title: string
  created_at: string
}

export function HistoryScreen() {
  const [loading, setLoading] =
    useState(true)

  const [activities, setActivities] =
    useState<ActivityItem[]>([])

  const [currencyCode, setCurrencyCode] =
    useState("NGN")

  const [currencySymbol, setCurrencySymbol] =
    useState("₦")

  const [period, setPeriod] =
    useState("today")

  const getDateFilter = () => {
    const now = new Date()

    if (period === "today") {
      return now.toISOString()
    }

    if (period === "week") {
      return new Date(
        now.getTime() - 7 * 86400000
      ).toISOString()
    }

    if (period === "month") {
      return new Date(
        now.getTime() - 30 * 86400000
      ).toISOString()
    }

    return null
  }

  useEffect(() => {
    const loadHistory = async () => {
      try {
        setLoading(true)

        const factoryId =
          getFactoryId()

        if (!factoryId) return

        const currency =
          await getFactoryCurrency()

        setCurrencyCode(currency.code)
        setCurrencySymbol(
          currency.symbol
        )

        const dateFilter =
          getDateFilter()

        // SALES
        const { data: sales } =
          await supabase
            .from("sales")
            .select("*")
            .eq(
              "factory_id",
              factoryId
            )
            .gte(
              "created_at",
              dateFilter
            )

        // EXPENSES
        const { data: expenses } =
          await supabase
            .from("expenses")
            .select("*")
            .eq(
              "factory_id",
              factoryId
            )
            .gte(
              "created_at",
              dateFilter
            )

        // PRODUCTION
        const {
          data: production,
        } = await supabase
          .from("production")
          .select("*")
          .eq(
            "factory_id",
            factoryId
          )
          .gte(
            "created_at",
            dateFilter
          )

        // LOANS
        const { data: loans } =
          await supabase
            .from("loans")
            .select("*")
            .eq(
              "factory_id",
              factoryId
            )
            .gte(
              "created_at",
              dateFilter
            )

        // BANK
        const { data: bank } =
          await supabase
            .from("bank")
            .select("*")
            .eq(
              "factory_id",
              factoryId
            )
            .gte(
              "created_at",
              dateFilter
            )

        let combined: ActivityItem[] =
          []

        // SALES
        sales?.forEach((item) => {
          combined.push({
            type: "sale",
            title: `Sale — ${
              item.customer_name ||
              "Customer"
            }`,
            amount:
              item.total_amount,
            created_at:
              item.created_at,
          })
        })

        // EXPENSES
        expenses?.forEach(
          (item) => {
            combined.push({
              type: "expense",
              title: `Expense — ${
                item.category ||
                "Expense"
              }`,
              amount: item.amount,
              created_at:
                item.created_at,
            })
          }
        )

        // PRODUCTION
        production?.forEach(
          (item) => {
            combined.push({
              type: "production",
              title: `Production — ${item.bags_produced} bags`,
              created_at:
                item.created_at,
            })
          }
        )

        // LOANS
        loans?.forEach((item) => {
          combined.push({
            type: "loan",
            title: `Loan — ${
              item.description ||
              "Loan"
            }`,
            amount: item.amount,
            created_at:
              item.created_at,
          })
        })

        // BANK
        bank?.forEach((item) => {
          combined.push({
            type: "bank",
            title: `Bank — ${
              item.description ||
              "Transaction"
            }`,
            amount: item.amount,
            created_at:
              item.created_at,
          })
        })

        // SORT DESC
        combined.sort(
          (a, b) =>
            new Date(
              b.created_at
            ).getTime() -
            new Date(
              a.created_at
            ).getTime()
        )

        setActivities(combined)

      } catch (error) {
        console.error(error)

      } finally {
        setLoading(false)
      }
    }

    loadHistory()
  }, [period])

  return (
    <div className="p-4 space-y-5 pb-24">

      {/* HEADER */}
      <div>
        <h1 className="text-2xl font-bold">
          Activity History
        </h1>

        <p className="text-sm text-gray-500">
          Complete operational timeline
        </p>
      </div>

      {/* FILTERS */}
      <div className="flex gap-2 flex-wrap">

        {[
          {
            key: "today",
            label: "Today",
          },
          {
            key: "week",
            label: "Week",
          },
          {
            key: "month",
            label: "Month",
          },
        ].map((p) => (
          <button
            key={p.key}
            onClick={() =>
              setPeriod(p.key)
            }
            className={`px-3 py-1.5 rounded-lg text-sm ${
              period === p.key
                ? "bg-[#2563eb] text-white"
                : "bg-white border border-gray-200"
            }`}
          >
            {p.label}
          </button>
        ))}

      </div>

      {/* LOADING */}
      {loading && (
        <div className="text-sm text-gray-500">
          Loading history...
        </div>
      )}

      {/* EMPTY */}
      {!loading &&
        activities.length === 0 && (
          <div className="bg-white rounded-2xl p-5 shadow-sm text-sm text-gray-500">
            No activity found.
          </div>
        )}

      {/* TIMELINE */}
      <div className="space-y-3">

        {activities.map(
          (item, index) => (
            <div
              key={index}
              className="bg-white rounded-2xl p-4 shadow-sm"
            >

              <div className="flex items-start justify-between gap-3">

                <div>
                  <p className="font-semibold capitalize">
                    {item.title}
                  </p>

                  <p className="text-xs text-gray-500 mt-1">
                    {new Date(
                      item.created_at
                    ).toLocaleString()}
                  </p>
                </div>

                {item.amount !==
                  undefined && (
                  <p className="font-semibold">
                    {formatCurrency(
                      item.amount,
                      currencyCode,
                      currencySymbol
                    )}
                  </p>
                )}

              </div>

            </div>
          )
        )}

      </div>

    </div>
  )
}